        /// Get Metrics &lt;p&gt;Get API metrics rows. These are records of each REST API call.&lt;/p&gt; &lt;p&gt;require CanReadMetrics role&lt;/p&gt; &lt;p&gt;&lt;strong&gt;NOTE: Automatic from_date Default&lt;/strong&gt;&lt;/p&gt; &lt;p&gt;If you do not provide a &lt;code&gt;from_date&lt;/code&gt; parameter, this endpoint will automatically set it to:&lt;br /&gt; &lt;strong&gt;now - 9 minutes ago&lt;/strong&gt;&lt;/p&gt; &lt;p&gt;This prevents accidentally querying all metrics since Unix Epoch and ensures reasonable response times.&lt;br /&gt; For historical/reporting queries, always explicitly specify your desired &lt;code&gt;from_date&lt;/code&gt;.&lt;/p&gt; &lt;p&gt;&lt;strong&gt;IMPORTANT: Smart Caching &amp;amp; Performance&lt;/strong&gt;&lt;/p&gt; &lt;p&gt;This endpoint uses intelligent two-tier caching to optimize performance:&lt;/p&gt; &lt;p&gt;&lt;strong&gt;Stable Data Cache (Long TTL):&lt;/strong&gt;&lt;br /&gt; - Metrics older than 600 seconds (10 minutes) are considered immutable/stable&lt;br /&gt; - These are cached for 86400 seconds (24 hours)&lt;br /&gt; - Used when your query&#39;s from_date is older than the stable boundary&lt;/p&gt; &lt;p&gt;&lt;strong&gt;Recent Data Cache (Short TTL):&lt;/strong&gt;&lt;br /&gt; - Recent metrics (within the stable boundary) are cached for 7 seconds&lt;br /&gt; - Used when your query includes recent data or has no from_date&lt;/p&gt; &lt;p&gt;&lt;strong&gt;STRONGLY RECOMMENDED: Always specify from_date in your queries!&lt;/strong&gt;&lt;/p&gt; &lt;p&gt;&lt;strong&gt;Why from_date matters:&lt;/strong&gt;&lt;br /&gt; - Queries WITH from_date older than 10 mins → cached for 24 hours (fast!)&lt;br /&gt; - Queries WITHOUT from_date → cached for only 7 seconds (slower)&lt;/p&gt; &lt;p&gt;&lt;strong&gt;Examples:&lt;/strong&gt;&lt;br /&gt; - &lt;code&gt;from_date&#x3D;2025-01-01T00:00:00.000Z&lt;/code&gt; → Uses 24 hours cache (historical data)&lt;br /&gt; - &lt;code&gt;from_date&#x3D;1100-01-01T01:01:01.000Z&lt;/code&gt; (recent date) → Uses 7 seconds cache (recent data)&lt;br /&gt; - No from_date → &lt;strong&gt;Automatically set to 9 minutes ago&lt;/strong&gt; → Uses 7 seconds cache (recent data)&lt;/p&gt; &lt;p&gt;For best performance on historical/reporting queries, always include a from_date parameter!&lt;/p&gt; &lt;p&gt;Filters Part 1.&lt;em&gt;filtering&lt;/em&gt; (no wilde cards etc.) parameters to GET /management/metrics&lt;/p&gt; &lt;p&gt;You can filter by the following fields by applying url parameters&lt;/p&gt; &lt;p&gt;eg: /management/metrics?from_date&#x3D;1100-01-01T01:01:01.000Z&amp;amp;to_date&#x3D;1100-01-01T01:01:01.000Z&amp;amp;limit&#x3D;50&amp;amp;offset&#x3D;2&lt;/p&gt; &lt;p&gt;1 from_date e.g.:from_date&#x3D;1100-01-01T01:01:01.000Z&lt;br /&gt; &lt;strong&gt;DEFAULT&lt;/strong&gt;: If not provided, automatically set to now - 9 minutes (keeps queries in recent data zone)&lt;br /&gt; &lt;strong&gt;IMPORTANT&lt;/strong&gt;: Including from_date enables long-term caching for historical data queries!&lt;/p&gt; &lt;p&gt;2 to_date e.g.:to_date&#x3D;1100-01-01T01:01:01.000Z Defaults to a far future date i.e. Sat Jan 01 00:00:00 UTC 4000&lt;/p&gt; &lt;p&gt;3 limit (for pagination: defaults to 50)  eg:limit&#x3D;200&lt;/p&gt; &lt;p&gt;4 offset (for pagination: zero index, defaults to 0) eg: offset&#x3D;10&lt;/p&gt; &lt;p&gt;5 sort_by (defaults to date field) eg: sort_by&#x3D;date&lt;br /&gt; possible values:&lt;br /&gt; &amp;quot;url&amp;quot;,&lt;br /&gt; &amp;quot;date&amp;quot;,&lt;br /&gt; &amp;quot;username&amp;quot; (or &amp;quot;user_name&amp;quot; for backward compatibility),&lt;br /&gt; &amp;quot;app_name&amp;quot;,&lt;br /&gt; &amp;quot;developer_email&amp;quot;,&lt;br /&gt; &amp;quot;implemented_by_partial_function&amp;quot;,&lt;br /&gt; &amp;quot;implemented_in_version&amp;quot;,&lt;br /&gt; &amp;quot;consumer_id&amp;quot;,&lt;br /&gt; &amp;quot;verb&amp;quot;&lt;/p&gt; &lt;p&gt;6 direction (defaults to date desc) eg: direction&#x3D;desc&lt;/p&gt; &lt;p&gt;eg: /management/metrics?from_date&#x3D;1100-01-01T01:01:01.000Z&amp;amp;to_date&#x3D;1100-01-01T01:01:&lt;a href&#x3D;\&quot;m&amp;#x61;i&amp;#108;&amp;#116;o&amp;#58;&amp;#48;&amp;#x31;&amp;#46;&amp;#x30;&amp;#48;&amp;#48;&amp;#90;&amp;#x26;l&amp;#x69;&amp;#x6d;&amp;#105;&amp;#x74;&amp;#x3d;&amp;#49;&amp;#x30;&amp;#48;&amp;#48;&amp;#x30;&amp;#x26;&amp;#x6f;&amp;#x66;f&amp;#x73;&amp;#101;&amp;#x74;&#x3D;&amp;#x30;&amp;#x26;an&amp;#111;&amp;#110;&#x3D;&amp;#x66;&amp;#97;&amp;#108;se&amp;#x26;&amp;#97;&amp;#112;&amp;#112;&amp;#x5f;&amp;#110;&amp;#97;&amp;#109;&amp;#x65;&amp;#x3d;&amp;#x54;&amp;#101;&amp;#97;&amp;#116;&amp;#x41;&amp;#112;&amp;#112;&amp;#x26;i&amp;#x6d;&amp;#x70;&amp;#x6c;&amp;#x65;&amp;#x6d;&amp;#x65;&amp;#110;t&amp;#101;&amp;#100;_&amp;#105;&amp;#x6e;&amp;#x5f;&amp;#118;e&amp;#x72;&amp;#x73;&amp;#x69;o&amp;#x6e;&amp;#x3d;v&amp;#50;&amp;#x2e;&amp;#x31;&amp;#46;&amp;#48;&amp;amp;v&amp;#101;&amp;#114;&amp;#98;&#x3D;&amp;#80;OS&amp;#x54;&amp;#x26;us&amp;#101;&amp;#x72;&amp;#x5f;&amp;#105;&amp;#x64;&amp;#61;&amp;#99;&amp;#x37;&amp;#x62;&amp;#x36;&amp;#x63;&amp;#98;47&amp;#45;&amp;#99;&amp;#98;&amp;#57;&amp;#54;&amp;#x2d;&amp;#x34;&amp;#x34;&amp;#x34;&amp;#x31;-8&amp;#x38;0&amp;#49;&amp;#45;&amp;#51;&amp;#53;&amp;#x62;&amp;#x35;&amp;#x37;4&amp;#x35;&amp;#54;&amp;#55;53&amp;#x61;&amp;amp;u&amp;#115;&amp;#101;&amp;#114;&amp;#x6e;&amp;#97;m&amp;#101;&amp;#61;&amp;#115;&amp;#x75;&amp;#115;&amp;#97;&amp;#x6e;&amp;#x2e;&amp;#117;&amp;#x6b;&amp;#46;&amp;#50;&amp;#x39;&amp;#64;e&amp;#120;a&amp;#x6d;p&amp;#x6c;e.&amp;#x63;&amp;#111;&amp;#109;\&quot;&gt;&amp;#x30;&amp;#49;&amp;#46;&amp;#48;&amp;#48;&amp;#48;&amp;#90;&amp;#x26;li&amp;#109;&amp;#x69;&amp;#116;&amp;#x3d;&amp;#x31;00&amp;#48;&amp;#48;&amp;#x26;&amp;#x6f;&amp;#102;f&amp;#x73;&amp;#x65;&amp;#x74;&amp;#61;&amp;#x30;&amp;#38;&amp;#x61;&amp;#x6e;&amp;#111;&amp;#110;&amp;#61;&amp;#x66;&amp;#x61;&amp;#x6c;s&amp;#101;&amp;#x26;&amp;#97;&amp;#x70;&amp;#x70;&amp;#95;&amp;#x6e;&amp;#97;&amp;#x6d;&amp;#x65;&amp;#x3d;&amp;#84;ea&amp;#x74;&amp;#x41;&amp;#x70;&amp;#112;&amp;#x26;&amp;#105;m&amp;#112;&amp;#x6c;&amp;#101;&amp;#109;&amp;#101;&amp;#110;t&amp;#x65;&amp;#100;&amp;#x5f;&amp;#x69;&amp;#110;&amp;#95;&amp;#x76;&amp;#101;&amp;#114;&amp;#x73;&amp;#x69;&amp;#111;n&#x3D;&amp;#118;&amp;#x32;&amp;#46;&amp;#x31;&amp;#46;&amp;#x30;&amp;amp;&amp;#x76;&amp;#x65;r&amp;#x62;&amp;#61;&amp;#x50;&amp;#x4f;&amp;#83;&amp;#84;&amp;amp;u&amp;#x73;er&amp;#95;i&amp;#x64;&amp;#61;&amp;#99;7&amp;#x62;&amp;#x36;cb&amp;#x34;&amp;#55;-&amp;#x63;&amp;#98;&amp;#x39;&amp;#x36;&amp;#45;&amp;#x34;&amp;#x34;4&amp;#x31;&amp;#45;&amp;#56;&amp;#x38;&amp;#48;1&amp;#x2d;&amp;#51;&amp;#x35;&amp;#x62;5&amp;#55;&amp;#52;&amp;#53;&amp;#54;&amp;#x37;&amp;#x35;&amp;#51;&amp;#97;&amp;#x26;&amp;#117;&amp;#115;&amp;#101;&amp;#114;&amp;#110;&amp;#97;&amp;#109;&amp;#x65;&amp;#61;&amp;#x73;&amp;#117;&amp;#x73;&amp;#x61;&amp;#110;&amp;#46;&amp;#117;&amp;#x6b;&amp;#46;&amp;#x32;&amp;#57;@&amp;#x65;&amp;#x78;&amp;#x61;&amp;#109;&amp;#112;le&amp;#x2e;&amp;#x63;&amp;#111;&amp;#x6d;&lt;/a&gt;&amp;amp;consumer_id&#x3D;78&lt;/p&gt; &lt;p&gt;Other filters:&lt;/p&gt; &lt;p&gt;7 consumer_id  (if null ignore)&lt;/p&gt; &lt;p&gt;8 user_id (if null ignore)&lt;/p&gt; &lt;p&gt;9 anon (if null ignore) only support two value : true (return where user_id is null.) or false (return where user_id is not null.)&lt;/p&gt; &lt;p&gt;10 url (if null ignore), note: can not contain &#39;&amp;amp;&#39;.&lt;/p&gt; &lt;p&gt;11 app_name (if null ignore)&lt;/p&gt; &lt;p&gt;12 implemented_by_partial_function (if null ignore),&lt;/p&gt; &lt;p&gt;13 implemented_in_version (if null ignore)&lt;/p&gt; &lt;p&gt;14 verb (if null ignore)&lt;/p&gt; &lt;p&gt;15 correlation_id (if null ignore)&lt;/p&gt; &lt;p&gt;16 duration (if null ignore) - Returns calls where duration &amp;gt; specified value (in milliseconds). Use this to find slow API calls. eg: duration&#x3D;5000 returns calls taking more than 5 seconds&lt;/p&gt; &lt;p&gt;User Authentication is Required. The User must be logged in. The Application must also be authenticated.&lt;/p&gt; &lt;p&gt;&lt;strong&gt;JSON response body fields:&lt;/strong&gt;&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#app_name\&quot;&gt;&lt;strong&gt;app_name&lt;/strong&gt;&lt;/a&gt;: appNameBank&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#\&quot;&gt;&lt;strong&gt;consumer_id&lt;/strong&gt;&lt;/a&gt;: 7uy8a7e4-6d02-40e3-a129-0b2bf89de8uh&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#\&quot;&gt;&lt;strong&gt;correlation_id&lt;/strong&gt;&lt;/a&gt;: 1flssoftxq0cr1nssr68u0mioj&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#\&quot;&gt;&lt;strong&gt;date&lt;/strong&gt;&lt;/a&gt;: 2020-01-27&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#developer_email\&quot;&gt;&lt;strong&gt;developer_email&lt;/strong&gt;&lt;/a&gt;:&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#duration\&quot;&gt;&lt;strong&gt;duration&lt;/strong&gt;&lt;/a&gt;: 5.123&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#implemented_by_partial_function\&quot;&gt;&lt;strong&gt;implemented_by_partial_function&lt;/strong&gt;&lt;/a&gt;:&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#implemented_in_version\&quot;&gt;&lt;strong&gt;implemented_in_version&lt;/strong&gt;&lt;/a&gt;:&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#metrics\&quot;&gt;&lt;strong&gt;metrics&lt;/strong&gt;&lt;/a&gt;:&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#\&quot;&gt;&lt;strong&gt;operation_id&lt;/strong&gt;&lt;/a&gt;: OBPv6.0.0-getBanks&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#\&quot;&gt;&lt;strong&gt;response_body&lt;/strong&gt;&lt;/a&gt;: response_body&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#\&quot;&gt;&lt;strong&gt;source_ip&lt;/strong&gt;&lt;/a&gt;: source_ip&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#\&quot;&gt;&lt;strong&gt;target_ip&lt;/strong&gt;&lt;/a&gt;: target_ip&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#\&quot;&gt;&lt;strong&gt;url&lt;/strong&gt;&lt;/a&gt;: &lt;a href&#x3D;\&quot;http://www.example.com/id-docs/123/image.png\&quot;&gt;http://www.example.com/id-docs/123/image.png&lt;/a&gt;&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#\&quot;&gt;&lt;strong&gt;user_id&lt;/strong&gt;&lt;/a&gt;: 9ca9a7e4-6d02-40e3-a129-0b2bf89de9b1&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#\&quot;&gt;&lt;strong&gt;username&lt;/strong&gt;&lt;/a&gt;: felixsmith&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#verb\&quot;&gt;&lt;strong&gt;verb&lt;/strong&gt;&lt;/a&gt;:&lt;/p&gt; 
        /// </summary>
        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="IGetMetricsApiResponse"/>&gt;</returns>
        public async Task<IGetMetricsApiResponse?> GetMetricsOrDefaultAsync(System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await GetMetricsAsync(cancellationToken).ConfigureAwait(false);
            }
            catch (Exception)
            {
                return null;
            }
        }

        /// <summary>
        /// Get Metrics &lt;p&gt;Get API metrics rows. These are records of each REST API call.&lt;/p&gt; &lt;p&gt;require CanReadMetrics role&lt;/p&gt; &lt;p&gt;&lt;strong&gt;NOTE: Automatic from_date Default&lt;/strong&gt;&lt;/p&gt; &lt;p&gt;If you do not provide a &lt;code&gt;from_date&lt;/code&gt; parameter, this endpoint will automatically set it to:&lt;br /&gt; &lt;strong&gt;now - 9 minutes ago&lt;/strong&gt;&lt;/p&gt; &lt;p&gt;This prevents accidentally querying all metrics since Unix Epoch and ensures reasonable response times.&lt;br /&gt; For historical/reporting queries, always explicitly specify your desired &lt;code&gt;from_date&lt;/code&gt;.&lt;/p&gt; &lt;p&gt;&lt;strong&gt;IMPORTANT: Smart Caching &amp;amp; Performance&lt;/strong&gt;&lt;/p&gt; &lt;p&gt;This endpoint uses intelligent two-tier caching to optimize performance:&lt;/p&gt; &lt;p&gt;&lt;strong&gt;Stable Data Cache (Long TTL):&lt;/strong&gt;&lt;br /&gt; - Metrics older than 600 seconds (10 minutes) are considered immutable/stable&lt;br /&gt; - These are cached for 86400 seconds (24 hours)&lt;br /&gt; - Used when your query&#39;s from_date is older than the stable boundary&lt;/p&gt; &lt;p&gt;&lt;strong&gt;Recent Data Cache (Short TTL):&lt;/strong&gt;&lt;br /&gt; - Recent metrics (within the stable boundary) are cached for 7 seconds&lt;br /&gt; - Used when your query includes recent data or has no from_date&lt;/p&gt; &lt;p&gt;&lt;strong&gt;STRONGLY RECOMMENDED: Always specify from_date in your queries!&lt;/strong&gt;&lt;/p&gt; &lt;p&gt;&lt;strong&gt;Why from_date matters:&lt;/strong&gt;&lt;br /&gt; - Queries WITH from_date older than 10 mins → cached for 24 hours (fast!)&lt;br /&gt; - Queries WITHOUT from_date → cached for only 7 seconds (slower)&lt;/p&gt; &lt;p&gt;&lt;strong&gt;Examples:&lt;/strong&gt;&lt;br /&gt; - &lt;code&gt;from_date&#x3D;2025-01-01T00:00:00.000Z&lt;/code&gt; → Uses 24 hours cache (historical data)&lt;br /&gt; - &lt;code&gt;from_date&#x3D;1100-01-01T01:01:01.000Z&lt;/code&gt; (recent date) → Uses 7 seconds cache (recent data)&lt;br /&gt; - No from_date → &lt;strong&gt;Automatically set to 9 minutes ago&lt;/strong&gt; → Uses 7 seconds cache (recent data)&lt;/p&gt; &lt;p&gt;For best performance on historical/reporting queries, always include a from_date parameter!&lt;/p&gt; &lt;p&gt;Filters Part 1.&lt;em&gt;filtering&lt;/em&gt; (no wilde cards etc.) parameters to GET /management/metrics&lt;/p&gt; &lt;p&gt;You can filter by the following fields by applying url parameters&lt;/p&gt; &lt;p&gt;eg: /management/metrics?from_date&#x3D;1100-01-01T01:01:01.000Z&amp;amp;to_date&#x3D;1100-01-01T01:01:01.000Z&amp;amp;limit&#x3D;50&amp;amp;offset&#x3D;2&lt;/p&gt; &lt;p&gt;1 from_date e.g.:from_date&#x3D;1100-01-01T01:01:01.000Z&lt;br /&gt; &lt;strong&gt;DEFAULT&lt;/strong&gt;: If not provided, automatically set to now - 9 minutes (keeps queries in recent data zone)&lt;br /&gt; &lt;strong&gt;IMPORTANT&lt;/strong&gt;: Including from_date enables long-term caching for historical data queries!&lt;/p&gt; &lt;p&gt;2 to_date e.g.:to_date&#x3D;1100-01-01T01:01:01.000Z Defaults to a far future date i.e. Sat Jan 01 00:00:00 UTC 4000&lt;/p&gt; &lt;p&gt;3 limit (for pagination: defaults to 50)  eg:limit&#x3D;200&lt;/p&gt; &lt;p&gt;4 offset (for pagination: zero index, defaults to 0) eg: offset&#x3D;10&lt;/p&gt; &lt;p&gt;5 sort_by (defaults to date field) eg: sort_by&#x3D;date&lt;br /&gt; possible values:&lt;br /&gt; &amp;quot;url&amp;quot;,&lt;br /&gt; &amp;quot;date&amp;quot;,&lt;br /&gt; &amp;quot;username&amp;quot; (or &amp;quot;user_name&amp;quot; for backward compatibility),&lt;br /&gt; &amp;quot;app_name&amp;quot;,&lt;br /&gt; &amp;quot;developer_email&amp;quot;,&lt;br /&gt; &amp;quot;implemented_by_partial_function&amp;quot;,&lt;br /&gt; &amp;quot;implemented_in_version&amp;quot;,&lt;br /&gt; &amp;quot;consumer_id&amp;quot;,&lt;br /&gt; &amp;quot;verb&amp;quot;&lt;/p&gt; &lt;p&gt;6 direction (defaults to date desc) eg: direction&#x3D;desc&lt;/p&gt; &lt;p&gt;eg: /management/metrics?from_date&#x3D;1100-01-01T01:01:01.000Z&amp;amp;to_date&#x3D;1100-01-01T01:01:&lt;a href&#x3D;\&quot;m&amp;#x61;i&amp;#108;&amp;#116;o&amp;#58;&amp;#48;&amp;#x31;&amp;#46;&amp;#x30;&amp;#48;&amp;#48;&amp;#90;&amp;#x26;l&amp;#x69;&amp;#x6d;&amp;#105;&amp;#x74;&amp;#x3d;&amp;#49;&amp;#x30;&amp;#48;&amp;#48;&amp;#x30;&amp;#x26;&amp;#x6f;&amp;#x66;f&amp;#x73;&amp;#101;&amp;#x74;&#x3D;&amp;#x30;&amp;#x26;an&amp;#111;&amp;#110;&#x3D;&amp;#x66;&amp;#97;&amp;#108;se&amp;#x26;&amp;#97;&amp;#112;&amp;#112;&amp;#x5f;&amp;#110;&amp;#97;&amp;#109;&amp;#x65;&amp;#x3d;&amp;#x54;&amp;#101;&amp;#97;&amp;#116;&amp;#x41;&amp;#112;&amp;#112;&amp;#x26;i&amp;#x6d;&amp;#x70;&amp;#x6c;&amp;#x65;&amp;#x6d;&amp;#x65;&amp;#110;t&amp;#101;&amp;#100;_&amp;#105;&amp;#x6e;&amp;#x5f;&amp;#118;e&amp;#x72;&amp;#x73;&amp;#x69;o&amp;#x6e;&amp;#x3d;v&amp;#50;&amp;#x2e;&amp;#x31;&amp;#46;&amp;#48;&amp;amp;v&amp;#101;&amp;#114;&amp;#98;&#x3D;&amp;#80;OS&amp;#x54;&amp;#x26;us&amp;#101;&amp;#x72;&amp;#x5f;&amp;#105;&amp;#x64;&amp;#61;&amp;#99;&amp;#x37;&amp;#x62;&amp;#x36;&amp;#x63;&amp;#98;47&amp;#45;&amp;#99;&amp;#98;&amp;#57;&amp;#54;&amp;#x2d;&amp;#x34;&amp;#x34;&amp;#x34;&amp;#x31;-8&amp;#x38;0&amp;#49;&amp;#45;&amp;#51;&amp;#53;&amp;#x62;&amp;#x35;&amp;#x37;4&amp;#x35;&amp;#54;&amp;#55;53&amp;#x61;&amp;amp;u&amp;#115;&amp;#101;&amp;#114;&amp;#x6e;&amp;#97;m&amp;#101;&amp;#61;&amp;#115;&amp;#x75;&amp;#115;&amp;#97;&amp;#x6e;&amp;#x2e;&amp;#117;&amp;#x6b;&amp;#46;&amp;#50;&amp;#x39;&amp;#64;e&amp;#120;a&amp;#x6d;p&amp;#x6c;e.&amp;#x63;&amp;#111;&amp;#109;\&quot;&gt;&amp;#x30;&amp;#49;&amp;#46;&amp;#48;&amp;#48;&amp;#48;&amp;#90;&amp;#x26;li&amp;#109;&amp;#x69;&amp;#116;&amp;#x3d;&amp;#x31;00&amp;#48;&amp;#48;&amp;#x26;&amp;#x6f;&amp;#102;f&amp;#x73;&amp;#x65;&amp;#x74;&amp;#61;&amp;#x30;&amp;#38;&amp;#x61;&amp;#x6e;&amp;#111;&amp;#110;&amp;#61;&amp;#x66;&amp;#x61;&amp;#x6c;s&amp;#101;&amp;#x26;&amp;#97;&amp;#x70;&amp;#x70;&amp;#95;&amp;#x6e;&amp;#97;&amp;#x6d;&amp;#x65;&amp;#